import sailpoint.object.Identity;
import sailpoint.object.Link;
import sailpoint.object.Application;
import java.util.List;

List appNames = new ArrayList();
if(selectedIdentity!=null)
{
	Identity id = context.getObject(Identity.class,selectedIdentity);
	List links = id.getLinks();
	if(links != null)
	{
	  for (Link link : links )
	  {
	     appNames.add(link.getApplicationName());
	  }
	return appNames;
	}
}

                import sailpoint.object.Identity;
                import sailpoint.object.Application;
                import sailpoint.object.Link;
                import java.util.List;
                import sailpoint.api.IdentityService;
                import sailpoint.api.SailpointContext;


                String displayName = "";
                if( selectedIdentity != null && selectedApp != null )
                {
				  Identity identityObj = context.getObject(Identity.class,selectedIdentity);
                  Application appObj = context.getObjectByName(Application.class,selectedApp);
	  			  IdentityService service = new IdentityService(context);
				  if ( identityObj != null && appObj != null )
                  {
                    List links = service.getLinks(identityObj,appObj);
                    if( links != null && links.size()>0 )
                    {
                      Link link = links.get(0);
                      displayName = link.getDisplayName();
                    }
                  }
                  return displayName;
                }

                import sailpoint.object.Identity;
                import sailpoint.object.Application;
                import sailpoint.object.Link;
                import java.util.List;
                import sailpoint.api.IdentityService;
                import sailpoint.api.SailpointContext;


                String nativeId = "";
                if( selectedIdentity != null && selectedApp != null )
                {
				  Identity identityObj = context.getObject(Identity.class,selectedIdentity);
                  Application appObj = context.getObjectByName(Application.class,selectedApp);
				  IdentityService service = new IdentityService(context);

                  if ( identityObj != null && appObj != null )
                  {
                    List links = service.getLinks(identityObj,appObj);
                    if( links != null && links.size()>0 )
                    {
                      Link link = links.get(0);
                      nativeId = link.getNativeIdentity();
                    }
                   }
                   return nativeId;
                 }

        import java.lang.Object;
        import sailpoint.object.Application;
        import sailpoint.object.Attributes;
        import sailpoint.object.Custom;
        import sailpoint.object.Identity;
        import sailpoint.object.Link;
        import sailpoint.object.ResourceObject;
        import sailpoint.object.TaskResult;
        import sailpoint.object.Rule;
        import sailpoint.api.Aggregator;
        import sailpoint.connector.Connector;
        import sailpoint.tools.Message;
        import sailpoint.connector.ConnectorFactory;

        import org.apache.log4j.Logger; 
        import org.apache.log4j.Level;

        Logger log = Logger.getLogger("workflow.Custom-Targetted-Aggregation");
        String msgSeparator = "*";

        Connector appConnector = null;
        ResourceObject rObj= null;
        public ResourceObject getResourceObject(Application appObject ,String nativeIdentity) {
        ResourceObject rObj= null;
        appConnector = sailpoint.connector.ConnectorFactory.getConnector(appObject, null);
        rObj = appConnector.getObject("account",nativeIdentity, null);
        return rObj;
        }  

        String nativeIdentity =nativeidentity;
        String appName=selectedApp;

        Application appObject = context.getObjectByName(Application.class,appName);

        ResourceObject rObj = getResourceObject(appObject,nativeIdentity);
		Attributes argMap = new Attributes();

        argMap.put("aggregationType", "account");
        argMap.put("applications" ,appName);
        argMap.put("descriptionAttribute","description");
        argMap.put("descriptionLocale", "en_US");
        argMap.put("promoteAttributes",   "true");
        argMap.put("correlateEntitlements",   "true");
        argMap.put("checkDeleted",   "true");
        argMap.put("promoteManagedAttributes",   "true");

        Aggregator agg = new Aggregator(context, argMap);
        TaskResult result = agg.aggregate(appObject,rObj);

        if ( log.isTraceEnabled() ) {
        log.trace( msgSeparator );
        log.trace( "Task Result "+result.toXml());
        }
        return result;
